def _shape_key(inputs: dict[str, Any]) -> tuple[int, int, int, int, int, bool]:
    return (int(inputs['B']), int(inputs['Q']), int(inputs['M']), int(inputs['D']), int(inputs['K']), bool(inputs.get('self_search', False)))

def _require_tensor(inputs: dict[str, Any], name: str, *, shape: tuple[int, ...], dtype: str) -> Any:
    tensor = inputs.get(name)
    if tensor is None:
        raise ValueError(''.join(['09a4 full-bucket portfolio requires tensor ', format(repr(name), '')]))
    actual_shape = tuple((int(dim) for dim in tensor.shape))
    if actual_shape != shape:
        raise ValueError(''.join(['09a4 full-bucket portfolio requires ', format(name, ''), '.shape == ', format(repr(shape), ''), '; got ', format(repr(actual_shape), '')]))
    if str(tensor.dtype) != dtype:
        raise ValueError(''.join(['09a4 full-bucket portfolio requires ', format(name, ''), '.dtype == ', format(dtype, ''), '; got ', format(str(tensor.dtype), '')]))
    if not tensor.is_contiguous():
        raise ValueError(''.join(['09a4 full-bucket portfolio requires contiguous ', format(name, '')]))
    if str(tensor.device).split(':', 1)[0] != 'cuda':
        raise ValueError(''.join(['09a4 full-bucket portfolio requires CUDA ', format(name, ''), '; got ', format(str(tensor.device), '')]))
    return tensor

def _require_owned_key(inputs: dict[str, Any]) -> tuple[int, int, int, int, int, bool]:
    key = _shape_key(inputs)
    if key not in _BINDING_BY_KEY:
        raise ValueError(''.join(['09a4 full-bucket portfolio supports only the exact request-owned 16-row denominator; got ', format(repr(key), '')]))
    if bool(inputs.get('force_fallback', False)):
        raise ValueError('09a4 full-bucket portfolio has no forced fallback')
    arch = detect_gpu_arch()
    if arch not in {'sm_100a', 'sm_103a'}:
        raise ValueError(''.join(['09a4 full-bucket portfolio requires sm_100a or sm_103a; got ', format(repr(arch), '')]))
    bsz, q_rows, m_rows, dim, top_k, _ = key
    queries = _require_tensor(inputs, 'queries', shape=(bsz, q_rows, dim), dtype='torch.bfloat16')
    database = _require_tensor(inputs, 'database', shape=(bsz, m_rows, dim), dtype='torch.bfloat16')
    out_distances = _require_tensor(inputs, 'out_distances', shape=(bsz, q_rows, top_k), dtype='torch.float32')
    out_indices = _require_tensor(inputs, 'out_indices', shape=(bsz, q_rows, top_k), dtype='torch.int32')
    devices = {str(tensor.device) for tensor in (queries, database, out_distances, out_indices)}
    if len(devices) != 1:
        raise ValueError(''.join(['09a4 full-bucket portfolio requires inputs and outputs on one device; got ', format(repr(sorted(devices)), '')]))
    return key

def _binding(inputs: dict[str, Any]) -> dict[str, Any]:
    return _BINDING_BY_KEY[_require_owned_key(inputs)]

def selected_route(inputs: dict[str, Any]) -> str:
    binding = _binding(inputs)
    label = _LABEL_BY_KEY[_shape_key(inputs)]
    route = str(binding['module'].selected_route(inputs))
    expected = _EXPECTED_ROUTE_BY_LABEL[label]
    if route != expected:
        raise RuntimeError(''.join(['09a4 seed guard failed for ', format(label, ''), ': selected route ', format(repr(route), ''), '; expected ', format(repr(expected), '')]))
    return route

def selected_route_name(inputs: dict[str, Any]) -> str:
    return selected_route(inputs)

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    key = _require_owned_key(inputs)
    label = _LABEL_BY_KEY[key]
    binding = _BINDING_BY_KEY[key]
    seed_info = dict(binding['module'].route_info(inputs))
    route = selected_route(inputs)
    seed_entrypoint = seed_info.get('selected_entrypoint')
    if seed_entrypoint != binding['entrypoint']:
        raise RuntimeError(''.join(['09a4 seed entrypoint mismatch for ', format(label, ''), ': got ', format(repr(seed_entrypoint), ''), ', expected ', format(repr(binding['entrypoint']), '')]))
    exact_guard = ''.join(['dtype == bfloat16 and contiguous CUDA inputs/outputs and exact (B,Q,M,D,K,self_search) == ', format(repr(key), ''), ' and force_fallback == false and arch in {sm_100a,sm_103a}'])
    return {**seed_info, 'route': route, 'selected_route': route, 'selected_entrypoint': ENTRYPOINT, 'seed_entrypoint': binding['entrypoint'], 'selected_seed': binding['seed_id'], 'expected_seed': binding['seed_id'], 'source_task': binding['source_task'], 'source_commit': binding['source_commit'], 'source_path': binding['source_path'], 'expected_route': _EXPECTED_ROUTE_BY_LABEL[label], 'route_kind': 'specialized', 'route_source': 'shape-specific-seed', 'classification': 'route-ok', 'coverage_class': 'full_bucket_exact_seed_portfolio', 'candidate_surface': PORTFOLIO_ID, 'portfolio_entrypoint': ENTRYPOINT, 'portfolio_guard_id': ''.join(['09a4_exact_', format(label, '')]), 'portfolio_guard': exact_guard, 'seed_guard_id': seed_info.get('guard_id'), 'seed_guard': seed_info.get('selected_guard'), 'guard_id': ''.join(['09a4_exact_', format(label, '')]), 'selected_guard': exact_guard, 'guard_order': list(TARGET_LABELS), 'fallback': None, 'forced_fallback': False, 'coverage_only': False, 'production_policy': 'weave_only', 'external_fallback': None, 'missing_weave_route': False, 'caller_owned_outputs': True}

def route_trace_entry(label: str, inputs: dict[str, Any]) -> dict[str, Any]:
    key = _require_owned_key(inputs)
    expected_label = _LABEL_BY_KEY[key]
    if label != expected_label:
        raise ValueError(''.join(['09a4 route trace label mismatch: got ', format(repr(label), ''), ', expected ', format(repr(expected_label), '')]))
    return {'label': label, 'shape_key': label, 'B': key[0], 'Q': key[1], 'M': key[2], 'D': key[3], 'K': key[4], 'self_search': key[5], **route_info(inputs)}

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    binding = _binding(inputs)
    selected_route(inputs)
    outputs = binding['module'].launch_for_eval(inputs)
    distances = outputs.get('distances', outputs.get('out_distances'))
    indices = outputs.get('indices', outputs.get('out_indices'))
    if distances is not inputs['out_distances'] or indices is not inputs['out_indices']:
        raise RuntimeError('09a4 seed did not return the caller-owned output objects')
    return {'distances': distances, 'indices': indices}
launch_for_eval.route_info = route_info
